using System;
using System.Linq;

class Program
{
    static void Main(string[] args)
    {
        var parts = Console.ReadLine().Split('|');
        int[] arr = parts[0].Trim().Split(' ').Select(int.Parse).ToArray();
        int x = int.Parse(parts[1].Trim());
        int lo = 0, hi = arr.Length - 1, ans = -1;
        while (lo <= hi)
        {
            int mid = (lo + hi) / 2;
            if (arr[mid] <= x) { ans = mid; lo = mid + 1; }
            else hi = mid - 1;
        }
        Console.WriteLine(ans >= 0 ? arr[ans].ToString() : "-1");
    }
}

