        Console.WriteLine(string.Join(" ", result));
    }
}

using System;

class Program
{
    static void Main(string[] args)
    {
        string[] parts = Console.ReadLine().Split(' ');
        int L = int.Parse(parts[0]), R = int.Parse(parts[1]);
        for (int n = L; n <= R; n++)
        {
            int root = (int)Math.Sqrt(n);
            if (root * root != n) continue;
            bool isPrime = root >= 2;
            for (int d = 2; d * d <= root; d++)
                if (root % d == 0) { isPrime = false; break; }
            if (isPrime) Console.Write(n + " ");
        }
    }
}

using System;
using System.Collections.Generic;

class Program
{
    static void Main(string[] args)
    {
        int n = int.Parse(Console.ReadLine());
        var seen = new HashSet<int>();
        while (n != 1 && !seen.Contains(n))
        {
            seen.Add(n);
            int sum = 0;
            while (n > 0) { int d = n % 10; sum += d * d; n /= 10; }
            n = sum;
        }
        Console.WriteLine(n == 1 ? "true" : "false");
    }
}

using System;
using System.Linq;

class Program
{
    static void Main(string[] args)
    {
        string s = Console.ReadLine();
        int[][] mat = s.Trim('[', ']').Split('},{')
            .Select(row => row.Split(',').Select(int.Parse).ToArray()).ToArray();
        int rows = mat.Length, cols = mat[0].Length;
        int[] rowMin = mat.Select(r => r.Min()).ToArray();
        for (int i = 0; i < rows; i++)
            for (int j = 0; j < cols; j++)
            {
                bool maxInCol = true;
                for (int k = 0; k < rows; k++)
                    if (mat[k][j] > mat[i][j]) { maxInCol = false; break; }
                if (maxInCol && mat[i][j] == rowMin[i])
                {
                    Console.WriteLine(mat[i][j]);
                    return;
                }
            }
    }
}

